INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-39f5e973-moex-00219', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '有關固態硬碟（solid-statedisk,SSD）的敘述，下列何者錯誤？', '["目前市售的SSD所使用的技術以快閃記憶體（flashmemory）為主", "以快閃記憶體製成的SSD除了作為儲存裝置亦常作為主記憶體使用", "SSD沒有需要移動的機械元件，因此抵抗震動的能力比傳統硬碟佳", "SSD讀寫資料時不需要搜尋時間（seektime）與旋轉延遲（rotational latency），因此隨機存取（random access）的效能比傳統硬碟好"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00220', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '某個中央處理單元（CentralProcessingUnit,CPU）的時脈速度（ClockRate）為1GHz，假設一個時脈週期 （ClockCycle）可以執行一個指令，理想情況下該處理器一秒內可以執行多少指令？', '["109", "1030", "29", "230"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00221', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '儲存在硬碟裡的資料，有可能會遭遇到硬性錯誤（harderror）與軟性錯誤（softerror），有關錯誤類型的定 義，下列何者正確？', '["硬性錯誤將造成硬體損壞，軟性錯誤將造成軟體強制終止", "硬性錯誤是由硬體故障造成的，軟性錯誤是由程式錯誤（bug）導致的", "硬性錯誤將造成資料的流失，軟性錯誤可能透過錯誤更正碼（error-correctingcode,ECC）或其他方式修正", "硬性錯誤的發生是無法避免的，軟性錯誤的發生是可以避免的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00222', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '設以管道化（Pipelining）機制改善中央處理單元（CentralProcessingUnit,CPU）效能時，且管道中包含五個 步驟：指令執行（InstructionExecute）、指令解碼（InstructionDecode）、記憶體存取（MemoryAccess）、結果 寫回（ResultWriteBack）與指令擷取（InstructionFetch）。通常處理器以何種步驟的順序完成一道指令的執行？', '["指令執行、記憶體存取、結果寫回、指令擷取與指令解碼", "指令解碼、記憶體存取、指令執行、結果寫回與指令擷取", "指令擷取、指令解碼、指令執行、記憶體存取與結果寫回", "結果寫回、記憶體存取、指令擷取、指令解碼與指令執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00223', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '關於SRAM與DRAM的敘述，下列何者錯誤？', '["SRAM的結構較複雜，因此需要有再充電（Refresh）的動作保持所儲存的資料內容", "DRAM單位面積內的儲存容量較多", "SRAM適合做為暫存器和快取記憶體使用", "DRAM採用電容儲存資料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00224', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '某處理器執行某程式時，平均每個指令耗時5ns，如果以百萬指令每秒（millioninstructionspersecond,MIPS） 呈現該處理器對該程式的速度，則下列何者正確？', '["2MIPS", "20MIPS", "200MIPS", "2000MIPS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00225', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '有關虛擬記憶體（virtualmemory）與實體記憶體（physicalmemory）的敘述，下列何者正確？', '["任一程序的虛擬記憶體空間不得大於電腦中實體記憶體的大小", "電腦中實體記憶體的大小不得大於任一程序的虛擬記憶體空間", "若一個要被使用的虛擬記憶體位址未對應到一個實體記憶體位址，則會發生分頁錯失（pagefault）", "虛擬記憶體多由靜態隨機存取記憶體（staticrandomaccessmemory,SRAM）組成，實體記憶體多由動態 隨機存取記憶體（dynamicrandomaccessmemory,DRAM）組成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00226', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '對於處理器中暫存器（Register）的敘述，下列何者錯誤？', '["常數暫存器未必需要用到記憶體元件", "索引（Index）暫存器是位址暫存器的一種", "通用目的暫存器（GeneralPurposeRegisters）可以儲存資料或位址", "向量暫存器用來儲存由向量處理器執行MIMD指令所得到的資料"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00227', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '若使用IEEE-754單精確度格式表示浮點數，則一浮點數使用幾個欄位來表示？', '["2", "3", "4", "5"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00228', 'pukao-39f5e973', 'pukao-39f5e973-moex-110-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '將十進制數-2468 以四個十六進制位數及2的補數（2''scomplement）表示時，其表示法為何？ 10', '["F62C", "F6CC", "F65C", "F64C"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "14b29f1b1063", "answer_pdf_sha1": "2de69e704cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "451", "s": "1217", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL)
